// =============================================================================
// Types
// =============================================================================

/** Unavailability event types */
type UnavailabilityType = 'CORRECTIVE' | 'INCIDENT' | 'COLLISION' | 'VANDALISM' | 'EXTERNAL' | 'PLANNED_OUTAGE';

/** Event status */
