/**
 * MMS Service Demand Service
 *
 * Manages fleet availability requirements - a CRITICAL v2.1 service.
 * Service demand is a HARD CONSTRAINT for the optimizer: schedules that
 * violate minimum train availability must be rejected.
 *
 * Key responsibilities:
 * - Define minimum train requirements by fleet, day type, and time period
 * - Validate that proposed PM schedules don't violate availability
 * - Calculate default demand (85% of fleet) when no explicit config exists
 * - Support peak period requirements (AM, midday, PM, evening)
 *
 * Business rules:
 * - Optimizer CANNOT schedule PM that would drop fleet below minTrainsRequired
 * - Day types: WEEKDAY, SATURDAY, SUNDAY, HOLIDAY
 * - Demand records are versioned by effectiveDate (most recent applies)
 * - Peak period requirements are optional but enforced if defined
 *
 * @see specs/003-database-schema.md Section 3.2.1 (Service Demand)
 * @see specs/004-domain-services.md Section 4.2.6 (Service Demand Service)
 */

import { eq, and, sql, desc, lte, count, inArray, gte } from 'drizzle-orm';
